type ShopFilter = 'all' | 'weapon' | 'defense' | 'potion';

export const ShopScreen: React.FC<{ player: Player, items: Item[], onBuy: (i: Item) => void, onSell: (i: Item) => void, onLeave: () => void }> = ({ player, items, onBuy, onSell, onLeave }) => {
  const [selectedItem, setSelectedItem] = useState<Item | null>(null);
  const [filter, setFilter] = useState<ShopFilter>('all');

  // Filter Logic
  const filteredItems = items.filter(item => {
      if (filter === 'all') return true;
      if (filter === 'weapon') return item.type === 'weapon';
      if (filter === 'potion') return item.type === 'potion';
      if (filter === 'defense') return ['armor', 'helmet', 'legs', 'shield'].includes(item.type);
      return true;
  });

  // Seleciona o primeiro item ao mudar filtro ou abrir
  useEffect(() => {
      if (filteredItems.length > 0 && (!selectedItem || !filteredItems.find(i => i.id === selectedItem.id))) {
          setSelectedItem(filteredItems[0]);
      } else if (filteredItems.length === 0) {
          setSelectedItem(null);
      }
  }, [filter, items]);

  return (
  <div className="absolute inset-0 z-40 bg-slate-950 text-white flex flex-col pointer-events-auto">
    <header className="bg-slate-900 border-b border-slate-800 p-4 flex justify-between items-center shadow-lg z-10 shrink-0">
      <div className="flex items-center gap-3">
        <div className="bg-amber-500/20 p-2 rounded-lg text-amber-500"><ShoppingBag /></div>
        <div>
           <h2 className="font-bold text-xl text-amber-100">Mercador do Vazio</h2>
           <p className="text-xs text-slate-500">Compre equipamentos ou venda seu espólio.</p>
        </div>
      </div>
      <div className="flex items-center gap-4">
         <div className="bg-black/40 px-4 py-2 rounded-full border border-slate-700 flex gap-2 items-center">
            <Coins className="text-amber-400 w-4 h-4" />
            <span className="font-mono text-amber-200">{player.gold}</span>
         </div>
         <button onClick={onLeave} className="px-4 py-2 bg-slate-800 hover:bg-slate-700 rounded font-bold flex items-center gap-2">
             <Home size={16}/> Voltar
         </button>
      </div>
    </header>

    <div className="flex-1 flex overflow-hidden">
        {/* LEFT: ITEMS LIST + FILTERS */}
        <div className="w-80 md:w-96 bg-slate-900 border-r border-slate-800 flex flex-col shrink-0">
            {/* Filter Tabs */}
            <div className="p-2 grid grid-cols-4 gap-1 border-b border-slate-800 bg-slate-950/50">
                <button onClick={() => setFilter('all')} className={`p-2 rounded flex items-center justify-center ${filter === 'all' ? 'bg-indigo-600 text-white' : 'bg-slate-800 text-slate-400 hover:bg-slate-700'}`} title="Todos"><Filter size={16}/></button>
                <button onClick={() => setFilter('weapon')} className={`p-2 rounded flex items-center justify-center ${filter === 'weapon' ? 'bg-amber-600 text-white' : 'bg-slate-800 text-slate-400 hover:bg-slate-700'}`} title="Armas"><Sword size={16}/></button>
                <button onClick={() => setFilter('defense')} className={`p-2 rounded flex items-center justify-center ${filter === 'defense' ? 'bg-blue-600 text-white' : 'bg-slate-800 text-slate-400 hover:bg-slate-700'}`} title="Defesa"><Shield size={16}/></button>
                <button onClick={() => setFilter('potion')} className={`p-2 rounded flex items-center justify-center ${filter === 'potion' ? 'bg-emerald-600 text-white' : 'bg-slate-800 text-slate-400 hover:bg-slate-700'}`} title="Consumíveis"><FlaskConical size={16}/></button>
            </div>

            <div className="flex-1 overflow-y-auto p-2 flex flex-col gap-2">
                <h3 className="font-bold text-xs text-slate-500 uppercase tracking-widest px-2 my-2">
                    {filter === 'all' ? 'Catálogo Completo' : filter === 'weapon' ? 'Arsenal' : filter === 'defense' ? 'Armaduras' : 'Alquimia'}
                </h3>
                {filteredItems.length === 0 && <div className="text-center text-slate-600 p-4 text-sm italic">Nada nesta categoria.</div>}

                {filteredItems.map(item => {
                    const isSelected = selectedItem?.id === item.id;
                    const rarityClass = getRarityColor(item.rarity);

                    return (
                        <div 
                            key={item.id} 
                            onClick={() => setSelectedItem(item)}
                            className={`flex items-center gap-3 p-3 rounded-lg cursor-pointer transition-all border-l-4 relative overflow-hidden
                                ${isSelected ? `${rarityClass} bg-slate-800` : `border-transparent bg-slate-800/50 text-slate-400 border-l-${item.rarity === 'gold' ? 'amber-500' : item.rarity === 'silver' ? 'slate-400' : 'orange-800'}`}
                                hover:bg-slate-800
                            `}
                        >
                            <div className="text-2xl relative z-10">{item.icon}</div>
                            <div className="flex-1 relative z-10">
                                <div className={`font-bold text-sm ${isSelected ? 'text-white' : 'text-slate-300'}`}>{item.name}</div>
                                <div className="flex justify-between items-center mt-1">
                                    <div className="text-[10px] font-mono opacity-70">{item.cost} G</div>
                                    <div className={`text-[9px] px-1.5 py-0.5 rounded uppercase font-bold border
                                        ${item.rarity === 'gold' ? 'border-amber-500/30 text-amber-400' : item.rarity === 'silver' ? 'border-slate-400/30 text-slate-300' : 'border-orange-700/30 text-orange-400'}
                                    `}>
                                        {item.rarity === 'bronze' ? 'Comum' : item.rarity === 'silver' ? 'Raro' : 'Lendário'}
                                    </div>
                                </div>
                            </div>
                            {isSelected && <MousePointerClick size={16} className="text-amber-500 relative z-10" />}
                        </div>
                    )
                })}
            </div>
        </div>

        {/* CENTER: 3D PREVIEW & DETAILS */}
        <div className="flex-1 bg-black/50 flex flex-col relative">
            {/* 3D Canvas Container */}
            <div className="flex-1 relative bg-gradient-to-b from-slate-900 to-slate-950 overflow-hidden flex items-center justify-center">
                {selectedItem ? (
                    <div className="w-full h-full absolute inset-0">
                         <ItemPreviewCanvas itemType={selectedItem.type} itemId={selectedItem.id} />
                         {/* Rarity Badge */}
                         <div className={`absolute top-4 right-4 px-3 py-1 rounded border text-xs font-bold uppercase tracking-widest backdrop-blur-sm shadow-lg ${getRarityColor(selectedItem.rarity)}`}>
                             {selectedItem.rarity.toUpperCase()}
                         </div>
                    </div>
                ) : (
                    <div className="text-slate-600 flex flex-col items-center gap-2">
                        <ShoppingBag size={48} />
                        <span>Selecione um item</span>
                    </div>
                )}
            </div>

            {/* Item Action Bar */}
            <div className="h-auto min-h-[120px] bg-slate-900 border-t border-slate-800 p-6 flex flex-col md:flex-row gap-6 items-center justify-between shrink-0">
                 {selectedItem && (
                     <>
                        <div className="flex-1">
                            <h2 className="text-2xl font-black text-white mb-1">{selectedItem.name}</h2>
                            <p className="text-slate-400 text-sm mb-2">{selectedItem.description}</p>
                            <div className="flex gap-4 text-xs font-mono">
                                <span className="bg-slate-800 px-2 py-1 rounded text-indigo-300">Min. Lvl {selectedItem.minLevel}</span>
                                <span className="bg-slate-800 px-2 py-1 rounded text-emerald-300">
                                    {selectedItem.type === 'weapon' ? `+${selectedItem.value} ATK` : 
                                     selectedItem.type === 'potion' ? `Recupera ${selectedItem.value}` : `+${selectedItem.value} DEF`}
                                </span>
                            </div>
                        </div>

                        <div className="flex items-center gap-4">
                             {(() => {
                                 const canAfford = player.gold >= selectedItem.cost;
                                 const hasLevel = player.level >= selectedItem.minLevel;
                                 const isEquipped = 
                                     (player.equippedWeapon?.id === selectedItem.id) || 
                                     (player.equippedArmor?.id === selectedItem.id) ||
                                     (player.equippedHelmet?.id === selectedItem.id) ||
                                     (player.equippedLegs?.id === selectedItem.id) ||
                                     (player.equippedShield?.id === selectedItem.id);

                                 return (
                                    <button 
                                        onClick={() => onBuy(selectedItem)}
                                        disabled={!canAfford || isEquipped || !hasLevel}
                                        className={`px-8 py-4 rounded-xl font-black text-lg shadow-xl transition-all flex items-center gap-3
                                            ${isEquipped ? 'bg-slate-800 text-slate-500 cursor-default' : 
                                            !hasLevel ? 'bg-slate-800 text-red-500 border border-red-900 cursor-not-allowed' :
                                            canAfford ? 'bg-indigo-600 hover:bg-indigo-500 text-white hover:scale-105' : 'bg-slate-800 text-slate-500'}
                                        `}
                                    >
                                        {isEquipped ? 
                                            <span>ITEM EQUIPADO</span> : 
                                         !hasLevel ? 
                                            <span>NÍVEL {selectedItem.minLevel} NECESSÁRIO</span> : 
                                         canAfford ? 
                                            <>COMPRAR POR <span className="text-amber-300">{selectedItem.cost} G</span></> : 
                                            <>FALTA OURO ({selectedItem.cost} G)</>
                                        }
                                    </button>
                                 )
                             })()}
                        </div>
                     </>
                 )}
            </div>
        </div>

        {/* RIGHT: INVENTORY SELL (COMPACT) */}
        <div className="w-64 bg-slate-950 border-l border-slate-900 overflow-y-auto p-4 hidden lg:block shrink-0">
            <h3 className="font-bold text-xs text-slate-500 uppercase tracking-widest mb-4 flex items-center gap-2"><DollarSign size={14}/> Vender Itens</h3>
            <div className="space-y-2">
                {Object.entries(player.inventory).map(([id, qty]) => {
                    if(qty <= 0) return null;
                    const itemDef = items.find(i => i.id === id);
                    if (!itemDef) return null;
                    const sellPrice = Math.floor(itemDef.cost / 2);
                    const rarityClass = getRarityColor(itemDef.rarity);

                    return (
                        <button 
                            key={id} 
                            onClick={() => onSell(itemDef)}
                            className={`w-full text-left bg-slate-900 hover:bg-red-900/20 hover:border-red-500/50 p-2 rounded border transition-all group ${rarityClass}`}
                        >
                            <div className="flex justify-between items-center mb-1">
                                <span className="text-xl">{itemDef.icon}</span>
                                <span className="bg-black/40 px-1.5 py-0.5 rounded text-[10px] text-white font-mono">x{qty}</span>
                            </div>
                            <div className="font-bold text-xs text-slate-300 truncate group-hover:text-white">{itemDef.name}</div>
                            <div className="text-[10px] text-slate-500 group-hover:text-red-300">Vender: {sellPrice} G</div>
                        </button>
                    )
                })}
            </div>
        </div>
    </div>
  </div>
  );
};

